import React from 'react';
import { FreeCamera, Vector3, HemisphericLight, Color4 } from '@babylonjs/core';
import "@babylonjs/loaders"
import { SceneLoader } from '@babylonjs/core/Loading/sceneLoader'
import SceneComponent from './jsx/SceneComponent';

let helmet
const onSceneReady = scene => {

  // Set clear color to transparent
  scene.clearColor = new Color4( 0.0, 0.0, 0.0, 0.0 )
  // This creates and positions a free camera (non-mesh)
  var camera = new FreeCamera("camera1", new Vector3(0, 0, -4), scene);
  // This targets the camera to scene origin
  camera.setTarget(Vector3.Zero());
  /* const canvas = */ scene.getEngine().getRenderingCanvas();
  // This attaches the camera to the canvas
  // camera.attachControl(canvas, true);
  // This creates a light, aiming 0,1,0 - to the sky (non-mesh)
  var light = new HemisphericLight("light", new Vector3(0, 1, 0), scene);
  // Default intensity is 1. Let's dim the light a small amount
  light.intensity = 0.7;
  // Import logo mesh
  SceneLoader.ImportMesh("", "./assets/models/", "DamagedHelmet.gltf", scene, function (meshes, particleSystems, skeletons) {
    // do something with the meshes and skeletons
    // particleSystems are always null for glTF assets
    helmet = meshes[0];

    helmet.position.y = 0
    helmet.rotation = new Vector3( 0, 0, 0 );

    scene.beforeRender = () => {
      helmet.rotation.y += 0.01;
    };
  });
  
}
/**
 * Will run on every frame render.  We are spinning the box on y-axis.
 */
const onRender = scene => {
  if (helmet !== undefined) {
    var deltaTimeInMillis = scene.getEngine().getDeltaTime();
    const rpm = 10;
    helmet.rotation.y += ((rpm / 60) * Math.PI * 2 * (deltaTimeInMillis / 1000));
  }
}

const result = (props) => (
  <div>
    <SceneComponent antialias adaptToDeviceRatio onSceneReady={onSceneReady} onRender={onRender} />
  </div>
)

export default result