import React from 'react'

class BodyComponent extends React.Component {
    constructor( props ) {
        super( props )
        this.state = {
            currentPage: "page-home"
        }
    }

    displayPage( page ) {
        this.setState({
            currentPage: page
        })
    }

    render() {
        return <div>
            { this.state.currentPage }
        </div>
    }
}

export default BodyComponent